class Solution:
    def printTree(self, root: Optional[TreeNode]) -> List[List[str]]:
        def height(n):
            return 0 if not n else 1+max(height(n.left),height(n.right))
        h=height(root); m=h+1; n=(1<<h)-1
        ans=[[""]*n for _ in range(m)]
        def dfs(node,r,c):
            if not node: return
            ans[r][c]=str(node.val)
            if node.left: dfs(node.left,r+1,c-2**(h-r-1))
            if node.right: dfs(node.right,r+1,c+2**(h-r-1))
        dfs(root,0,(n-1)//2); return ans

