class Solution {
    int H(TreeNode* n){ return n?1+max(H(n->left),H(n->right)):0; }
    void dfs(TreeNode* n,int r,int c,int p,vector<vector<string>>& a){
        if(!n) return; a[r][c]=to_string(n->val);
        if(n->left) dfs(n->left,r+1,c-p,p/2,a);
        if(n->right) dfs(n->right,r+1,c+p,p/2,a);
    }
public:
    vector<vector<string>> printTree(TreeNode* root){
        int h=H(root), m=h+1, w=(1<<h)-1;
        vector<vector<string>> a(m, vector<string>(w,""));
        dfs(root,0,(w-1)/2,(w+1)/4,a); return a;
    }
};
